Rules.InvariantScript:
Reset(Reviewer_Name);
Reset(VerificationStatusDropdown);

Set(showReviewErrors, false);

Switch(
    currentRole,

    "Volunteer",
        Navigate(VolunteerLandingPage, ScreenTransition.Fade),

    "Patrol Captain",
        Navigate(PatrolCaptainLandingPage, ScreenTransition.Fade),

    "Club Admin",
        Navigate(ClubAdminLandingPage, ScreenTransition.Fade)
)

If(
    IsBlank(Reviewer_Name.Text),

    Set(showReviewErrors, true);
    Notify("Please enter who reviewed this incident.", NotificationType.Error),

    Patch(
        Incidents,
        selectedIncident,
        {
            Status: {Value: VerificationStatusDropdown.Selected.Value},
            VerifiedBy: Reviewer_Name.Text,
            VerifiedAt: Now()
        }
    );

    Set(showReviewErrors, false);
    Notify("Review submitted successfully.", NotificationType.Success);
    Navigate(PatrolCaptainLandingPage, ScreenTransition.Fade)
)
